// Handle clicks outside the sidebar to close it on mobile
document.addEventListener('click', (event) => {
  const sidebar = document.getElementById('sidebar_section');
  const mobileMenuButton = document.querySelector('[data-weweb-uid="mobile_menu_button"]');

  if (sidebar && mobileMenuButton) {
    // Check if click is outside sidebar and not on the menu button
    if (!sidebar.contains(event.target) && !mobileMenuButton.contains(event.target)) {
      // Only close if we're on mobile/tablet view
      const windowWidth = window.innerWidth;
      if (windowWidth <= 1024 && sidebar.style.transform === 'translateX(0px)') {
        sidebar.style.transform = 'translateX(-240px)';
      }
    }
  }
});

// Handle window resize to adjust sidebar visibility
